class TokenStore:
    def __init__(self):
        self._lock = threading.Lock()
        self._tokens = {}  # token -> (username, expires_unix)

    def issue(self, username: str, ttl_seconds: int = 3600) -> pb2.LoginResponse:
        expires_unix = int(time.time()) + ttl_seconds
        token = f"devtoken:{username}:{expires_unix}"
        with self._lock:
            self._tokens[token] = (username, expires_unix)
        return pb2.LoginResponse(token=token, expires_unix=expires_unix)

    def validate(self, token: str) -> (bool, str):
        now = int(time.time())
        with self._lock:
            entry = self._tokens.get(token)
        if not entry:
            return False, ""
        username, expires_unix = entry
        if expires_unix < now:
            return False, ""
        return True, username


